{
  "test_runner": {
    "enabled": true,
    "parallel_execution": true,
    "max_workers": 4,
    "fail_fast": true,
    "max_failures": 1,
    "retry_flaky_tests": true,
    "max_retries": 3,
    "skip_test_files": true,
    "frameworks": {
      "jest": {
        "command": "npm test -- --findRelatedTests",
        "parallel": "--maxWorkers=4",
        "fail_fast": "--bail"
      },
      "vitest": {
        "command": "npx vitest run",
        "parallel": "--max-workers=4",
        "fail_fast": "--bail"
      },
      "pytest": {
        "command": "pytest",
        "parallel": "-n auto",
        "fail_fast": "--maxfail=1"
      },
      "go": {
        "command": "go test",
        "parallel": "-parallel 4",
        "timeout": "-timeout 30s"
      }
    },
    "file_extensions": ["js", "jsx", "ts", "tsx", "py", "go", "java"],
    "exclude_patterns": [
      "**/node_modules/**",
      "**/vendor/**",
      "**/__pycache__/**"
    ]
  }
}

